INSERT INTO quizzes (id, topic_id, title, title_hi, description, description_hi, difficulty, total_questions, time_limit_mins, is_previous_year, is_published, created_at) VALUES 
(1, 101, 'Prehistoric Age and Indus Valley Civilization Quiz 1', 'प्रागैतिहासिक काल और सिंधु घाटी सभ्यता प्रश्नोत्तरी 1', 'A comprehensive test covering paleolithic to chalcolithic ages and the Indus Valley Civilisation.', 'यह प्रश्नोत्तरी पुरापाषाण से लेकर ताम्रपाषाण काल और सिंधु घाटी सभ्यता तक के विषयों को कवर करती है।', 'Medium', 25, 25, 0, 1, '2026-03-12T02:41:34.000Z'),
(2, 101, 'Prehistoric Age and Indus Valley Civilization Quiz 2', 'प्रागैतिहासिक काल और सिंधु घाटी सभ्यता प्रश्नोत्तरी 2', 'Explore Harappan trade, burial practices, Chalcolithic cultures, and prehistoric tool evolution.', 'हड़प्पा व्यापार, शवाधान प्रथाओं, ताम्रपाषाण संस्कृतियों और प्रागैतिहासिक उपकरणों के विकास का अन्वेषण करें।', 'Medium', 25, 25, 0, 1, '2026-03-12T02:46:38.000Z'),
(3, 101, 'Prehistoric Age and Indus Valley Civilization Quiz 3', 'प्रागैतिहासिक काल और सिंधु घाटी सभ्यता प्रश्नोत्तरी 3', 'Dive deeper into Chalcolithic chiefdoms, Paleolithic discoveries, Harappan crafts, and megalithic transitions.', 'ताम्रपाषाणकालीन सरदारियों (चीफडम), पुरापाषाण खोजों, हड़प्पा शिल्पकला और महापाषाण संक्रमण के बारे में गहराई से जानें।', 'Medium', 25, 25, 0, 1, '2026-03-12T02:52:38.000Z'),
(4, 101, 'Prehistoric Age and Indus Valley Civilization Quiz 4', 'प्रागैतिहासिक काल और सिंधु घाटी सभ्यता प्रश्नोत्तरी 4', 'Advanced assessment of Chalcolithic transitions, late Harappan phases, IVC trade dynamics, and Paleolithic sites.', 'ताम्रपाषाण संक्रमण, उत्तर हड़प्पा चरणों, सिंधु घाटी व्यापार की गतिशीलता और पुरापाषाण स्थलों का उन्नत मूल्यांकन।', 'Medium', 25, 25, 0, 1, '2026-03-12T02:58:47.000Z');
